// Dremplay One heightmap world v2: supplied SW–NE 3×5 km island, continuous 8 m control lattice.
(()=>{const encoded='';globalThis.DREMPLAY_EXAMPLE_WORLD_READY=(async()=>{if(typeof DecompressionStream==='undefined')throw new Error('This browser cannot decode the pre-baked heightmap atlas.');const packed=new Uint8Array(encoded.length*3/4|0);let length=0;for(let at=0;at<encoded.length;at+=32768){const raw=atob(encoded.slice(at,Math.min(encoded.length,at+32768)));for(let i=0;i<raw.length;i++)packed[length++]=raw.charCodeAt(i);}const stream=new Blob([packed.subarray(0,length)]).stream().pipeThrough(new DecompressionStream('deflate')),bytes=new Uint8Array(await new Response(stream).arrayBuffer());if(bytes.length!==4512008)throw new Error('Heightmap atlas failed its length check.');globalThis.DREMPLAY_EXAMPLE_WORLD=Object.freeze({name:'SW–NE Heightmap Island',version:2,size:751,stride:8,stepVoxels:80,minVoxel:-30000,maxVoxel:30000,islandLengthMeters:5000,islandWidthMeters:3000,interpolation:'quintic-bilinear',bytes});return globalThis.DREMPLAY_EXAMPLE_WORLD;})();})();
